// // This module implements a 3-bit binary counter with enable and asynchronous reset. The counter decrements its value on the rising edge of the clock signal when the enable signal is active and resets to zero when the reset signal is active.
module binary_counter_3bit(
  input clk,
  input rst_n,
  input en,
  output reg [2:0] q
);

  always @(posedge clk or negedge rst_n) begin
    if (~rst_n)
      q <= 3'b000;
    else if (en)
      q <= q + 1;
  end

endmodule
